krpano.action:
if(isvalue(caller.linkedscene),

	if(caller.label !== '' AND caller.label !== null,
		copy(local.labeltext, caller.label);
	,
		copy(local.labeltext, scene[get(caller.linkedscene)].title);
	);
	if(local.labeltext,
		txtadd(local.lname, 'label_', get(caller.name));
		addlayer(get(local.lname));
		txtadd(layer[get(local.lname)].parent, 'hotspot[', get(caller.name), ']');
		set(layer[get(local.lname)].type, 'text');
		set(layer[get(local.lname)].align, 'center');
		set(layer[get(local.lname)].edge, 'bottom');
		set(layer[get(local.lname)].y, '-25');
		copy(layer[get(local.lname)].html, local.labeltext);
		set(layer[get(local.lname)].css, 'color:#FFFFFF; font-size:13px; text-align:center;');
		set(layer[get(local.lname)].textshadow, '1');
		set(layer[get(local.lname)].textshadowrange, '6');
		set(layer[get(local.lname)].textshadowangle, '90');
		set(layer[get(local.lname)].bg, 'true');
		set(layer[get(local.lname)].bgcolor, '0x000000');
		set(layer[get(local.lname)].bgalpha, '0.6');
		set(layer[get(local.lname)].bgroundedge, '4');
		set(layer[get(local.lname)].padding, '4 10');
		set(layer[get(local.lname)].enabled, 'false');
		set(layer[get(local.lname)].zorder, '1');
		set(layer[get(local.lname)].distorted, 'false');
	);
);

txtadd(tooltipname, 'tooltip_', get(name));
addplugin(get(tooltipname)); txtadd(plugin[get(tooltipname)].parent, 'hotspot[',get(name),']');
set(plugin[get(tooltipname)].url,'%SWFPATH%/plugins/textfield.swf');
set(plugin[get(tooltipname)].align,top); set(plugin[get(tooltipname)].edge,bottom);
set(plugin[get(tooltipname)].x,0); set(plugin[get(tooltipname)].y,0);
set(plugin[get(tooltipname)].width,200); set(plugin[get(tooltipname)].autoheight,true);
set(plugin[get(tooltipname)].background,false); set(plugin[get(tooltipname)].border,false);
set(plugin[get(tooltipname)].css,'text-align:center; color:#FFFFFF; font-family:Arial; font-weight:bold; font-size:16px;');
set(plugin[get(tooltipname)].textshadow,1); set(plugin[get(tooltipname)].textshadowrange,6.0); set(plugin[get(tooltipname)].textshadowangle,90);
copy(plugin[get(tooltipname)].html,hotspot[get(name)].tooltip);
set(plugin[get(tooltipname)].enabled,false);


calc(local.xframes, (caller.imagewidth /framewidth) BOR 0);
calc(local.frames, xframes * ((caller.imageheight / frameheight) BOR 0));
def(local.frame, integer, 0);


calc(caller.crop, '0|0|' + framewidth + '|' + frameheight);


setinterval(calc('crop_anim_' + caller.name), calc(1.0 / framerate),
	if(caller.loaded,
		inc(frame);
		if(frame GE frames, if(caller.onlastframe !== null, callwith(caller, onlastframe() ) ); set(frame,0); );
		mod(xpos, frame, xframes);
		div(ypos, frame, xframes);
		Math.floor(ypos);
		mul(xpos, framewidth);
		mul(ypos, frameheight);
		calc(caller.crop, xpos + '|' + ypos + '|' + framewidth + '|' + frameheight);
	  ,

		clearinterval(calc('crop_anim_' + caller.name));
	);
);

ifnot(isset(init),
	calc(xframes, (caller.imagewidth /framewidth) BOR 0);
	calc(frames, xframes * ((caller.imageheight / frameheight) BOR 0));
	def(frame, integer, 0);
	calc(caller.crop, '0|0|' + framewidth + '|' + frameheight);
	def(init,boolean,true);
	def(isruning,boolean,true);
,
	set(frame,0);
	if(isruning,break(););
);

setinterval(calc('crop_anim_' + caller.name), calc(1.0 / framerate),
	if(caller.loaded,
		inc(frame);
		if(frame GE frames, 
			if(caller.onlastframe !== null, 
				callwith(caller, onlastframe() ) 
			); 
			if(loop,
				set(frame,0); 
			,
				clearinterval(calc('crop_anim_' + caller.name));
				set(isruning,false);
				set(frame,calc(frames-1));
			);
		);

		if(frame == caller.eventframe,
			if(caller.onevent !== null,
				callwith(caller, onevent() );
			);
		);
		mod(xpos, frame, xframes);
		div(ypos, frame, xframes);
		Math.floor(ypos);
		mul(xpos, framewidth);
		mul(ypos, frameheight);
		calc(caller.crop, xpos + '|' + ypos + '|' + framewidth + '|' + frameheight);
	  ,

		clearinterval(calc('crop_anim_' + caller.name));
		set(isruning,false);
	);
);


